+    __aicore__ inline float FastExp(float x) const
+    {
+        constexpr float ln2 = 0.69314718056f;
+        if (x < -20.0f) {
+            return 0.0f;
+        }
+        if (x > 20.0f) {
+            x = 20.0f;
+        }
+
+        int32_t k = 0;
+        while (x > 0.5f * ln2) {
+            x -= ln2;
+            ++k;
+        }
+        while (x < -0.5f * ln2) {
+            x += ln2;
+            --k;
+        }
+
+        const float x2 = x * x;
+        const float x3 = x2 * x;
+        const float x4 = x3 * x;
+        const float x5 = x4 * x;
+        float result = 1.0f + x + 0.5f * x2 + 0.16666667f * x3 + 0.04166667f * x4 + 0.0083333333f * x5;
+        if (k > 0) {
+            for (int32_t i = 0; i < k; ++i) {
+                result *= 2.0f;
+            }
+        } else {
+            for (int32_t i = 0; i < -k; ++i) {
+                result *= 0.5f;
+            }
+        }
+        return result;
+    }
+
